// src/lib/discount.ts
export interface Cart {
  subtotal: number;
}

/**
 * Apply a percentage discount code to a cart subtotal.
 * Throws RangeError for an unknown code — the branch tests must exercise.
 */
export function applyDiscount(cart: Cart, code: string): number {
  const table: Record<string, number> = { SAVE10: 0.1, SAVE25: 0.25 };
  if (!(code in table)) {
    throw new RangeError(`unknown discount code: ${code}`);
  }
  const pct = table[code];
  return Math.round(cart.subtotal * (1 - pct) * 100) / 100;
}

// src/lib/discount.test.ts
import { describe, it, expect, vi } from "vitest";

// AP10 + Q13 fail: the module UNDER TEST is mocked, so the real applyDiscount()
// never runs — every assertion below verifies the mock, not production code.
vi.mock("./discount", () => ({
  applyDiscount: vi.fn(() => 90),
}));
import { applyDiscount } from "./discount";

describe("applyDiscount", () => {
  it("works", () => {
    const result = applyDiscount({ subtotal: 100 }, "SAVE10");
    // AP14 + Q4/Q15 fail: sole assertion is toBeTruthy on the mock's return.
    expect(result).toBeTruthy();
  });

  it("returns a number", () => {
    const input = 90;
    (applyDiscount as any).mockReturnValueOnce(input);
    const result = applyDiscount({ subtotal: 100 }, "SAVE25");
    // Q17 fail: asserts the value we just fed the mock — input echo, not computed.
    expect(result).toBe(input);
  });
});

// src/lib/slugify.ts
/**
 * Convert a title into a URL slug: lowercase, spaces→hyphens, strip non-alphanumerics,
 * collapse repeated hyphens. Throws RangeError on blank input.
 */
export function slugify(input: string): string {
  if (input.trim().length === 0) {
    throw new RangeError("slugify: input must be non-empty");
  }
  return input
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

// src/lib/slugify.test.ts
import { describe, it, expect } from "vitest";
import { slugify } from "./slugify";

describe("slugify", () => {
  it("lowercases and hyphenates a multi-word title", () => {
    expect(slugify("Hello World")).toBe("hello-world");
  });

  it("strips punctuation and collapses repeated separators", () => {
    expect(slugify("Rock & Roll!!!")).toBe("rock-roll");
  });

  it("trims leading and trailing separators produced by edge punctuation", () => {
    expect(slugify("  ...Draft... ")).toBe("draft");
  });

  it("preserves digits", () => {
    expect(slugify("Top 10 Songs")).toBe("top-10-songs");
  });

  it("throws RangeError with a descriptive message on blank input", () => {
    expect(() => slugify("   ")).toThrow(RangeError);
    expect(() => slugify("")).toThrow("input must be non-empty");
  });
});
